n run_pipeline(
        &self,
        query: &str,
        scope_id: &str,
        opts: Option<RetrievalOpts>,
        generate: bool,
    ) -> Result<RagResponse> {
        self.run_pipeline_with_budget(query, scope_id, opts, generate, None).await
    }
async fn run_pipeline_with_budget(
        &self,
        query: &str,
        scope_id: &str,
        opts: Option<RetrievalOpts>,
        generate: bool,
        token_override: Option<usize>,
    ) -> Result<RagResponse> {
        let trace_id = Uuid::now_v7();
        let pipeline_start = Instant::now();
        let mode = if generate { "ask" } else { "context" };

        info!(query, scope_id, mode, "rag_query_started");

        // --- Stage 1: Retrieval ---

        let mut retrieval_opts = opts.unwrap_or_else(|| {
            RetrievalOpts {
                limit: self.config.default_limit,
                expand_graph: self.config.graph_expand,
                graph_depth: self.config.graph_depth,
                ..Default::default()
            }
        });

        // Always apply config-level oversample when graph expansion is active.
        if retrieval_opts.expand_graph {
            retrieval_opts.oversample_factor = self.config.graph_oversample_factor;
        }
